\subsection{Top-supremum HModule transport (iter-049)}

The iter-048 carrier predicate $\Scheme.\IsCechAcyclicCover$ (\texttt{Cohomology/StructureSheafModuleK.lean}) lifts via its consumer $\mathtt{subsingleton\_HModule}'\_\mathtt{supr\_of\_isCechAcyclicCover}$ to a $\Subsingleton$ on $\HModulePrime\,k\,F\,n\,(\bigsqcup_i \mathcal U_i)$. This lives at universe $u$. The iter-053+ genus carrier $\Module.\mathtt{Finite}\,k\,(\HModule\,k\,(\toModuleKSheaf\,C)\,1)$, on the other hand, lives at universe $u+1$, since $\genus\,C = \mathrm{finrank}_k\,(\HModule\,k\,(\toModuleKSheaf\,C)\,1)$ (iter-011) is built on the universe-$u+1$ form $\HModule = \Ext_{u+1}\,((\mathtt{constantSheaf})\,(\ModuleCat.\mathtt{of}\,k\,k))\,F\,n$. The iter-034 universal bridge $\HModulePrime\,k\,F\,n\,T \equiv_{\Module k} \HModule\,k\,F\,n$ for terminal $T$ already crosses this gap. Iter-049 chains the two: under the cover-totality hypothesis $\bigsqcup_i \mathcal U_i = \top$, the iter-048 conclusion $\Subsingleton\,(\HModulePrime\,k\,F\,n\,(\bigsqcup\mathcal U))$ rewrites to $\Subsingleton\,(\HModulePrime\,k\,F\,n\,\top)$, which iter-034's bridge (composed with $\mathtt{Equiv.subsingleton}$) transports to $\Subsingleton\,(\HModule\,k\,F\,n)$. This is the universe-$u+1$ form of iter-048's vanishing, ready to be consumed by iter-053+.

\begin{theorem}[Top-supremum HModule transport, abstract sheaf form, iter-049]
  \label{thm:Scheme_subsingleton_HModule_of_isCechAcyclicCover_top}
  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule_of_isCechAcyclicCover_top}
  \uses{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover, def:Scheme_HModule_eq_HModule_prime_linearEquiv, def:Scheme_HModule, def:Scheme_HModule_prime}
  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathtt{of}\,k))$, and $F$ a sheaf of $\ModuleCat\,k$ on $\mathtt{Opens}\,C.\mathtt{left}.\mathtt{toTopCat}$. Assume both $\HasExt_u$ and $\HasExt_{u+1}$ on the same sheaf category. Let $\mathcal U : \iota \to \Opens\,C.\mathtt{left}.\mathtt{toTopCat}$ be a cover with $[\Scheme.\IsCechAcyclicCover\,F\,\mathcal U]$ and $\bigsqcup_i \mathcal U_i = \top$. Given an explicit comparison iso $\mathtt{compIso} : \forall n,\ \cechCohomology\,C\,F\,\mathcal U\,n \equiv_{k} \HModulePrime\,k\,F\,n\,(\bigsqcup_i \mathcal U_i)$ and $n \geq 1$, the underlying type of $\HModule\,k\,F\,n$ is a subsingleton.
\end{theorem}

\begin{proof}
  Apply the iter-048 consumer $\mathtt{subsingleton\_HModule}'\_\mathtt{supr\_of\_isCechAcyclicCover}$ (Theorem~\ref{thm:Scheme_subsingleton_HModule_prime_supr_of_isCechAcyclicCover}) to the iter-048 class $[\IsCechAcyclicCover\,F\,\mathcal U]$ + $\mathtt{compIso}$ + $n$ + the positivity $n \geq 1$, obtaining $\Subsingleton\,(\HModulePrime\,k\,F\,n\,(\bigsqcup_i \mathcal U_i))$. Rewrite via $h : \bigsqcup_i \mathcal U_i = \top$ (using $h \rhd \mathtt{this}$) to $\Subsingleton\,(\HModulePrime\,k\,F\,n\,\top)$. Apply the iter-034 universal bridge $\HModulePrime\_\mathtt{eq}\_\HModule\_\mathtt{linearEquiv}\,k\,F\,n\,(\mathtt{Preorder.isTerminalTop}\,\_)$ (Definition~\ref{def:Scheme_HModule_eq_HModule_prime_linearEquiv}) — which lifts the lattice's $\top$ to a categorical $\IsTerminal\,\top$ via Mathlib's $\Preorder.\mathtt{isTerminalTop}$ — to obtain a $\LinearEquiv$ between $\HModulePrime\,k\,F\,n\,\top$ and $\HModule\,k\,F\,n$. Pass through $.\mathtt{symm.toEquiv.subsingleton}$ to transport the $\Subsingleton$ structure across the iso, landing on $\HModule\,k\,F\,n$. Plan-agent $\mathtt{lean\_run\_code}$ probe (iter-049 pass) confirms the body $\mathtt{by\ haveI\ ::\ haveI\ ::\ exact\ \ldots}$ typechecks end-to-end with kernel-only axioms $[\propext, \mathtt{Classical.choice}, \mathtt{Quot.sound}]$.
\end{proof}

\begin{theorem}[Top-supremum HModule transport, curve form, iter-049]
  \label{thm:Scheme_subsingleton_HModule_of_isCechAcyclicCover_top_curve}
  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule_of_isCechAcyclicCover_top_curve}
  \uses{thm:Scheme_subsingleton_HModule_of_isCechAcyclicCover_top, def:Scheme_toModuleKSheaf}
  Let $k$ be a field and $C : \Over\,(\Spec\,(\CommRingCat.\mathtt{of}\,k))$. Assume both $\HasExt_u$ and $\HasExt_{u+1}$. Let $\mathcal U : \iota \to \Opens\,C.\mathtt{left}.\mathtt{toTopCat}$ with $[\Scheme.\IsCechAcyclicCover\,(\Scheme.\toModuleKSheaf\,C)\,\mathcal U]$ and $\bigsqcup_i \mathcal U_i = \top$. Given $\mathtt{compIso}$ at $F := \Scheme.\toModuleKSheaf\,C$ and $n \geq 1$, the underlying type of $\HModule\,k\,(\Scheme.\toModuleKSheaf\,C)\,n$ is a subsingleton.
\end{theorem}

\begin{proof}
  Direct application of Theorem~\ref{thm:Scheme_subsingleton_HModule_of_isCechAcyclicCover_top} to $F := \Scheme.\toModuleKSheaf\,C$ via the named-argument syntax $\mathtt{subsingleton\_HModule\_of\_isCechAcyclicCover\_top}\,(\mathcal U := \mathcal U)\,h\,\mathtt{compIso}\,n\,h_n$. Plan-agent $\mathtt{lean\_run\_code}$ probe (iter-049 pass) confirms kernel-only axioms.
\end{proof}

